mapper.select:
SELECT e.*, d.dept_name, p.position_name FROM sys_emp e LEFT JOIN sys_dept d ON e.dept_id = d.id LEFT JOIN sys_position p ON e.position_id = p.id
AND e.emp_name LIKE concat('%', #{empName}, '%')
AND e.dept_id = #{deptId}
AND e.emp_no LIKE concat('%', #{empNo}, '%')
AND e.emp_status = #{empStatus}
AND e.position_id = #{positionId}
ORDER BY e.create_time DESC

